{{CSS|content=
 @import url('https://fonts.googleapis.com/css2?family=Rock+Salt&display=swap');
.fandom-tilted-text {
  transform: rotate(-15deg); /* Tilts the text by -15 degrees */
  display: inline-block; /* Allows the element to be transformed */
}
 .tilt-text {
  display: inline-block;
  transform: rotate(-40deg); 
  transition: transform 0.3s ease;
}
.tilt-text:hover {
  transform: rotate(10deg); /* Tilt the text in the opposite direction when hovered */
}
.tilted-text {
  font-size: 3em;
  font-family: 'Arial', sans-serif;
  color: #fff;
  text-align: center;
  letter-spacing: 1px;
  text-transform: uppercase;
  position: relative;
  transform: perspective(500px) rotateX(15deg) rotateY(15deg);
  text-shadow: 2px 2px 5px rgba(0, 0, 0, 0.3), -2px -2px 5px rgba(0, 0, 0, 0.3);
  transition: transform 0.3s ease, text-shadow 0.3s ease;
}

.tilted-text:hover {
  transform: perspective(500px) rotateX(0deg) rotateY(0deg);
  text-shadow: 4px 4px 10px rgba(0, 0, 0, 0.4), -4px -4px 10px rgba(0, 0, 0, 0.4);
}

/* Additional styles for the page */
body {
  background-color: #111;
  color: #fff;
  font-family: 'Arial', sans-serif;
  margin: 0;
  padding: 0;
}

.container {
  display: flex;
  justify-content: center;
  align-items: center;
  height: 100vh;
  flex-direction: column;
}
.theme-fandomdesktop-dark .fandom-community-header__image img { opacity: 0; }
.fandom-community-header__image:before {
  content: '';
  background: url('https://static.wikia.nocookie.net/backrooms/images/8/88/Eye3.png/revision/latest/scale-to-width-down/480?cb=20231210041402&format=original') no-repeat;
  width: 250px;
  height: 250px;
  margin-left: 0.9em;
  margin-top: 2.5em;
  height: 80%;
  background-size: 80px;
  position: absolute;
  transition: 0s;
}
}}
